revisor_llm = ChatAnthropic(model="claude-sonnet-5")

def revisor_node(state: CritiqueState) -> dict:
    """Reads the draft and all critiques; produces an improved version."""    # Format critiques for the revisor
    critique_text = ""
    for c in state["critiques"]:
        issues = "\n".join(f"  - {i}" for i in c.issues) if c.issues else "  (none)"
        suggestions = "\n".join(f"  - {s}" for s in c.suggestions) if c.suggestions else "  (none)"
        critique_text += f"""
[{c.dimension.upper()} — score {c.score}/10]
Issues:
{issues}
Suggestions:
{suggestions}
"""

    prompt = f"""Original task: {state['task']}

Current draft:
---
{state['draft']}
---

Critiques received:
{critique_text}

Revise the draft to address ALL issues and suggestions above.
Preserve what was good; fix what was flagged.
Produce the complete revised version only (no meta-commentary)."""
    response = revisor_llm.invoke([
        SystemMessage(content="You are a precise revisor. Address every critique fully."),
        HumanMessage(content=prompt)
    ])

    return {
        "draft": response.content,          # the revised draft becomes the new draft
        "critiques": [],                    # clear critiques for next round
        "revision_count": state["revision_count"] + 1,
    }

CRITIC_THRESHOLDS = {
    "accuracy": 7,   # factual correctness — must be solid
    "safety": 8,     # safety is non-negotiable — higher bar
    "style": 6,      # style matters less — lower bar
}

def gate_with_per_dimension_thresholds(state: CritiqueState) -> dict:
    critiques_by_dim = {c.dimension: c for c in state["critiques"]}

    failing = []
    for dim, threshold in CRITIC_THRESHOLDS.items():
        critique = critiques_by_dim.get(dim)
        if critique and critique.score < threshold:
            failing.append(f"{dim}={critique.score}/{threshold}")

    at_max = state["revision_count"] >= state["max_revisions"]

    if not failing or at_max:
        if failing:
            print(f"Warning: accepted with failing critics: {failing}")
        return {"done": True, "final_output": state["draft"]}

    print(f"Re-revising due to: {failing}")
    return {}

def targeted_revisor(state: CritiqueState) -> dict:
    """Only address critiques from failing critics."""    failing_critiques = [
        c for c in state["critiques"]
        if c.score < CRITIC_THRESHOLDS.get(c.dimension, 7)
    ]

    if not failing_critiques:
        return {"done": True, "final_output": state["draft"]}

    focused_feedback = "\n".join(
        f"[{c.dimension}] Issues: {', '.join(c.issues)}. Suggestions: {', '.join(c.suggestions)}."
        for c in failing_critiques
    )

    response = revisor_llm.invoke([
        SystemMessage(content="You are a precise revisor. Fix only the specified issues."),
        HumanMessage(content=f"Task: {state['task']}\n\nDraft:\n{state['draft']}\n\nFix these specific issues:\n{focused_feedback}")
    ])

    return {
        "draft": response.content,
        "critiques": [],
        "revision_count": state["revision_count"] + 1,
    }

import pytest
from unittest.mock import patch, MagicMock

class TestGateNode:
    def _state(self, scores, revision_count=0, max_revisions=3, min_score=7):
        critiques = [Critique(f"c{i}", "dim", s, [], []) for i, s in enumerate(scores)]
        return {
            "task": "T", "draft": "D", "critiques": critiques,
            "revision_count": revision_count, "max_revisions": max_revisions,
            "min_acceptable_score": min_score, "done": False, "final_output": "",
        }

    def test_accepts_when_all_above_threshold(self):
        result = gate_node(self._state([8, 9, 7]))
        assert result["done"] is True

    def test_rejects_when_any_below_threshold(self):
        result = gate_node(self._state([8, 5, 9]))
        assert result.get("done") is not True

    def test_accepts_at_max_revisions(self):
        result = gate_node(self._state([5, 3, 4], revision_count=3, max_revisions=3))
        assert result["done"] is True

    def test_routing_to_revisor_when_failing(self):
        state = self._state([8, 4, 7])   # safety fails
        gate_result = gate_node(state)
        route = route_after_gate({**state, **gate_result})
        assert route == "revisor"

    def test_routing_to_end_when_passing(self):
        state = self._state([8, 8, 9])
        gate_result = gate_node(state)
        route = route_after_gate({**state, **gate_result})
        assert route == "__end__"
